package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.util.Collections;
import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    @Test
    public void testToString_withNonEmptyValues() throws Exception {
        String[] values = new String[] {"a", "b", "c"};
        Map<String, Integer> mapping = new HashMap<>();
        String comment = "comment";
        long recordNumber = 1L;

        CSVRecord record = createCSVRecord(values, mapping, comment, recordNumber);

        String expected = "[a, b, c]";
        String actual = record.toString();

        assertEquals(expected, actual);
    }

    @Test
    public void testToString_withEmptyValues() throws Exception {
        String[] values = new String[0];
        Map<String, Integer> mapping = Collections.emptyMap();
        String comment = null;
        long recordNumber = 0L;

        CSVRecord record = createCSVRecord(values, mapping, comment, recordNumber);

        String expected = "[]";
        String actual = record.toString();

        assertEquals(expected, actual);
    }

    private CSVRecord createCSVRecord(String[] values, Map<String, Integer> mapping, String comment, long recordNumber) throws Exception {
        Constructor<CSVRecord> constructor = CSVRecord.class.getDeclaredConstructor();
        constructor.setAccessible(true);
        CSVRecord record = constructor.newInstance();

        // Set the private final fields via reflection
        setFinalField(record, "values", values);
        setFinalField(record, "mapping", mapping);
        setFinalField(record, "comment", comment);
        setFinalField(record, "recordNumber", recordNumber);

        return record;
    }

    private void setFinalField(Object target, String fieldName, Object value) throws Exception {
        Field field = CSVRecord.class.getDeclaredField(fieldName);
        field.setAccessible(true);

        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        field.set(target, value);
    }
}
